package io.strimzi.crdgenerator;

import io.strimzi.api.annotations.ApiVersion;
import org.junit.jupiter.api.Test;

import java.io.IOException;
import java.io.StringWriter;

import static java.util.Collections.singletonList;
import static org.junit.jupiter.api.Assertions.assertTrue;

/**
 * Test for the @ExternalLink annotation support in DocGenerator.
 * This test verifies that when a property is annotated with @ExternalLink,
 * the generated documentation includes the external URL link.
 */
public class ExternalLinkTest {

    @Test
    public void testExternalLinkAnnotation() throws IOException {
        StringWriter w = new StringWriter();
        DocGenerator crdGenerator = new DocGenerator(ApiVersion.V1, 1, singletonList(ExternalLinkCrd.class), w, new KubeLinker("{KubeApiReferenceBase}"));
        crdGenerator.generate(ExternalLinkCrd.class);
        String s = w.toString();

        // Verify that the external link URL appears in the generated output
        assertTrue(s.contains("https://gateway-api.sigs.k8s.io/reference/spec/#"),
                "Expected external URL in generated docs");

        // Verify the property with @ExternalLink produces the expected output format
        assertTrue(s.contains("https://gateway-api.sigs.k8s.io/reference/spec/#gateway.networking.k8s.io/v1.HTTPRoute[HTTPRoute]"),
                "Expected external link format in generated docs");
    }
}
